create or replace function private.post_business_asset_journal_internal(p_business_id uuid,p_source_id uuid,p_entry_date date,p_source_type text,p_reference text,p_description text,p_lines jsonb) returns uuid language plpgsql security definer set search_path=pg_catalog,public,private as $$ declare actor_id uuid:=auth.uid(); base_currency text; fiscal_period_id uuid; journal_id uuid; line_item jsonb; line_no smallint:=0; account_id uuid; debit_amount numeric(24,6); credit_amount numeric(24,6); account_count integer; restore_ids uuid[]:='{}'::uuid[]; begin if actor_id is null then raise exception 'Authentication required.' using errcode='42501';end if; if p_source_type not in ('asset_capitalization','asset_depreciation','asset_disposal') then raise exception 'Unsupported fixed asset journal source.' using errcode='22023'; end if; if p_entry_date is null then raise exception 'Fixed asset journal date is required.' using errcode='22004';end if; if jsonb_typeof(p_lines)<>'array' or jsonb_array_length(p_lines)<2 or jsonb_array_length(p_lines)>200 then raise exception 'Fixed asset journals require 2 to 200 lines.' using errcode='22023'; end if; select business.base_currency into base_currency from public.businesses business where business.id=p_business_id and business.status='active'; if base_currency is null then raise exception 'Active business not found.' using errcode='P0002';end if; select period.id into fiscal_period_id from public.business_fiscal_periods period where period.business_id=p_business_id and period.status='open' and p_entry_date between period.starts_on and period.ends_on order by period.starts_on desc limit 1 for update; if fiscal_period_id is null then raise exception 'No open fiscal period contains the fixed asset journal date.' using errcode='22008';end if; select count(distinct account.id)::integer,coalesce(array_agg(account.id) filter(where not account.allow_manual_posting),'{}'::uuid[]) into account_count,restore_ids from public.business_chart_of_accounts account where account.business_id=p_business_id and account.is_active and account.id in (select (value->>'account_id')::uuid from jsonb_array_elements(p_lines)); if account_count<>(select count(distinct (value->>'account_id')::uuid) from jsonb_array_elements(p_lines)) then raise exception 'Fixed asset journal contains an inactive or invalid account.' using errcode='23514'; end if; perform 1 from public.business_chart_of_accounts account where account.business_id=p_business_id and account.id in (select (value->>'account_id')::uuid from jsonb_array_elements(p_lines)) for update; if cardinality(restore_ids)>0 then update public.business_chart_of_accounts set allow_manual_posting=true where business_id=p_business_id and id=any(restore_ids); end if; insert into public.business_journal_entries(business_id,entry_date,fiscal_period_id,source_type,source_id,reference,description,status,transaction_currency,exchange_rate,created_by) values(p_business_id,p_entry_date,fiscal_period_id,'manual',p_source_id,nullif(btrim(coalesce(p_reference,'')),''),btrim(p_description),'draft',base_currency,1,actor_id) returning id into journal_id; for line_item in select value from jsonb_array_elements(p_lines) loop line_no:=line_no+1; begin account_id:=(line_item->>'account_id')::uuid; debit_amount:=coalesce(nullif(line_item->>'debit','')::numeric,0); credit_amount:=coalesce(nullif(line_item->>'credit','')::numeric,0); exception when invalid_text_representation then raise exception 'Fixed asset journal lines contain invalid account or amount values.' using errcode='22023'; end; insert into public.business_journal_lines(business_id,journal_entry_id,line_number,account_id,description,debit_transaction,credit_transaction) values(p_business_id,journal_id,line_no,account_id,nullif(btrim(coalesce(line_item->>'description','')),''),debit_amount,credit_amount); end loop; update public.business_journal_entries set source_type=p_source_type where business_id=p_business_id and id=journal_id and status='draft'; if cardinality(restore_ids)>0 then update public.business_chart_of_accounts set allow_manual_posting=false where business_id=p_business_id and id=any(restore_ids); end if; update public.business_journal_entries set status='posted' where business_id=p_business_id and id=journal_id; return journal_id; end;$$;

create or replace function private.validate_business_asset_category_accounts(p_business_id uuid,p_category_id uuid) returns public.business_asset_categories language plpgsql stable security definer set search_path=pg_catalog,public as $$ declare category_record public.business_asset_categories%rowtype; begin select category.*into category_record from public.business_asset_categories category where category.business_id=p_business_id and category.id=p_category_id; if not found then raise exception 'Asset category not found.' using errcode='P0002';end if; if not exists(select 1 from public.business_chart_of_accounts where business_id=p_business_id and id=category_record.asset_account_id and is_active and account_type='asset' and normal_balance='debit') then raise exception 'Asset category requires an active debit-balance asset account.' using errcode='23514'; end if; if not exists(select 1 from public.business_chart_of_accounts where business_id=p_business_id and id=category_record.accumulated_depreciation_account_id and is_active and account_type='asset' and account_subtype='contra_asset' and normal_balance='credit') then raise exception 'Asset category requires an active accumulated depreciation contra-asset account.' using errcode='23514'; end if; if not exists(select 1 from public.business_chart_of_accounts where business_id=p_business_id and id=category_record.depreciation_expense_account_id and is_active and account_type='expense' and normal_balance='debit') then raise exception 'Asset category requires an active depreciation expense account.' using errcode='23514'; end if; return category_record; end;$$;

create or replace function private.upsert_business_asset_category_internal(p_business_id uuid,p_category_id uuid,p_code text,p_name text,p_description text,p_asset_account_id uuid,p_accumulated_depreciation_account_id uuid,p_depreciation_expense_account_id uuid,p_default_useful_life_months integer,p_default_residual_rate numeric,p_default_depreciation_convention text,p_active boolean default true) returns jsonb language plpgsql security definer set search_path=pg_catalog,public,private as $$ declare actor_id uuid:=auth.uid();category_record public.business_asset_categories%rowtype; begin if actor_id is null or not private.can_manage_business_assets(p_business_id) then raise exception 'Fixed asset management permission required.' using errcode='42501';end if; if not exists(select 1 from public.business_chart_of_accounts where business_id=p_business_id and id=p_asset_account_id and is_active and account_type='asset' and normal_balance='debit') then raise exception 'Select an active debit-balance asset account.' using errcode='23514';end if; if not exists(select 1 from public.business_chart_of_accounts where business_id=p_business_id and id=p_accumulated_depreciation_account_id and is_active and account_type='asset' and account_subtype='contra_asset' and normal_balance='credit') then raise exception 'Select an active accumulated depreciation contra-asset account.' using errcode='23514';end if; if not exists(select 1 from public.business_chart_of_accounts where business_id=p_business_id and id=p_depreciation_expense_account_id and is_active and account_type='expense' and normal_balance='debit') then raise exception 'Select an active depreciation expense account.' using errcode='23514';end if; perform set_config('app.business_asset_action','category_write',true); if p_category_id is null then insert into public.business_asset_categories(business_id,code,name,description,asset_account_id,accumulated_depreciation_account_id,depreciation_expense_account_id,default_useful_life_months,default_residual_rate,default_depreciation_convention,active,created_by,updated_by) values(p_business_id,upper(btrim(p_code)),btrim(p_name),nullif(btrim(coalesce(p_description,'')),''),p_asset_account_id,p_accumulated_depreciation_account_id,p_depreciation_expense_account_id,p_default_useful_life_months,coalesce(p_default_residual_rate,0),lower(btrim(p_default_depreciation_convention)),coalesce(p_active,true),actor_id,actor_id) returning*into category_record; else update public.business_asset_categories set code=upper(btrim(p_code)),name=btrim(p_name),description=nullif(btrim(coalesce(p_description,'')),''),asset_account_id=p_asset_account_id,accumulated_depreciation_account_id=p_accumulated_depreciation_account_id,depreciation_expense_account_id=p_depreciation_expense_account_id,default_useful_life_months=p_default_useful_life_months,default_residual_rate=coalesce(p_default_residual_rate,0),default_depreciation_convention=lower(btrim(p_default_depreciation_convention)),active=coalesce(p_active,true),updated_by=actor_id where business_id=p_business_id and id=p_category_id returning*into category_record; if not found then raise exception 'Asset category not found.' using errcode='P0002';end if; end if; perform private.write_business_asset_audit(p_business_id,null,null,case when p_category_id is null then 'asset_category_created' else 'asset_category_updated' end,jsonb_build_object('category_id',category_record.id,'code',category_record.code,'active',category_record.active)); return to_jsonb(category_record); exception when unique_violation then raise exception 'Asset category code is already in use.' using errcode='23505'; end;$$;

create or replace function private.upsert_business_fixed_asset_internal(p_business_id uuid,p_asset_id uuid,p_category_id uuid,p_branch_id uuid,p_asset_code text,p_name text,p_description text,p_serial_number text,p_location text,p_acquisition_date date,p_in_service_date date,p_original_cost numeric,p_residual_value numeric,p_useful_life_months integer,p_depreciation_convention text) returns jsonb language plpgsql security definer set search_path=pg_catalog,public,private as $$ declare actor_id uuid:=auth.uid();asset_record public.business_fixed_assets%rowtype;category_record public.business_asset_categories%rowtype; begin if actor_id is null or not private.can_manage_business_assets(p_business_id) then raise exception 'Fixed asset management permission required.' using errcode='42501';end if; category_record:=private.validate_business_asset_category_accounts(p_business_id,p_category_id); if not category_record.active then raise exception 'Asset category is inactive.' using errcode='22023';end if; perform private.validate_business_asset_branch(p_business_id,p_branch_id,actor_id,true); perform set_config('app.business_asset_action','asset_write',true); if p_asset_id is null then insert into public.business_fixed_assets(business_id,category_id,branch_id,asset_code,name,description,serial_number,location,acquisition_date,in_service_date,original_cost,residual_value,useful_life_months,depreciation_convention,book_value,created_by,updated_by) values(p_business_id,p_category_id,p_branch_id,upper(btrim(p_asset_code)),btrim(p_name),nullif(btrim(coalesce(p_description,'')),''),nullif(btrim(coalesce(p_serial_number,'')),''),nullif(btrim(coalesce(p_location,'')),''),p_acquisition_date,p_in_service_date,p_original_cost,coalesce(p_residual_value,0),p_useful_life_months,lower(btrim(p_depreciation_convention)),p_original_cost,actor_id,actor_id) returning*into asset_record; else select*into asset_record from public.business_fixed_assets where business_id=p_business_id and id=p_asset_id for update; if not found then raise exception 'Fixed asset not found.' using errcode='P0002';end if; if asset_record.status<>'draft' then raise exception 'Only draft fixed assets can be edited.' using errcode='55000';end if; update public.business_fixed_assets set category_id=p_category_id,branch_id=p_branch_id,asset_code=upper(btrim(p_asset_code)),name=btrim(p_name),description=nullif(btrim(coalesce(p_description,'')),''),serial_number=nullif(btrim(coalesce(p_serial_number,'')),''),location=nullif(btrim(coalesce(p_location,'')),''),acquisition_date=p_acquisition_date,in_service_date=p_in_service_date,original_cost=p_original_cost,residual_value=coalesce(p_residual_value,0),useful_life_months=p_useful_life_months,depreciation_convention=lower(btrim(p_depreciation_convention)),book_value=p_original_cost,updated_by=actor_id where business_id=p_business_id and id=p_asset_id returning*into asset_record; end if; perform private.write_business_asset_audit(p_business_id,asset_record.id,null,case when p_asset_id is null then 'fixed_asset_created' else 'fixed_asset_updated' end,jsonb_build_object('asset_code',asset_record.asset_code,'cost',asset_record.original_cost,'branch_id',asset_record.branch_id)); return to_jsonb(asset_record)||jsonb_build_object('asset_display_code','AST-'||lpad(asset_record.asset_no::text,8,'0')); exception when unique_violation then raise exception 'Fixed asset code is already in use.' using errcode='23505'; end;$$;

create or replace function private.activate_business_fixed_asset_internal(p_business_id uuid,p_asset_id uuid,p_counter_account_id uuid,p_posting_date date,p_reference text default null) returns jsonb language plpgsql security definer set search_path=pg_catalog,public,private as $$ declare actor_id uuid:=auth.uid();asset_record public.business_fixed_assets%rowtype;category_record public.business_asset_categories%rowtype;journal_id uuid; begin if actor_id is null or not private.can_manage_business_assets(p_business_id) then raise exception 'Fixed asset management permission required.' using errcode='42501';end if; select*into asset_record from public.business_fixed_assets where business_id=p_business_id and id=p_asset_id for update; if not found then raise exception 'Fixed asset not found.' using errcode='P0002';end if; if asset_record.status<>'draft' then raise exception 'Only draft fixed assets can be capitalized.' using errcode='55000';end if; perform private.validate_business_asset_branch(p_business_id,asset_record.branch_id,actor_id,true); category_record:=private.validate_business_asset_category_accounts(p_business_id,asset_record.category_id); if p_posting_date<asset_record.acquisition_date then raise exception 'Capitalization date cannot be before acquisition.' using errcode='22008';end if; if p_counter_account_id=category_record.asset_account_id then raise exception 'Capitalization counter account must differ from the asset account.' using errcode='22023';end if; if not exists(select 1 from public.business_chart_of_accounts where business_id=p_business_id and id=p_counter_account_id and is_active) then raise exception 'Capitalization counter account is unavailable.' using errcode='23514';end if; journal_id:=private.post_business_asset_journal_internal(p_business_id,p_asset_id,p_posting_date,'asset_capitalization',p_reference,'Capitalize '||asset_record.name,jsonb_build_array(jsonb_build_object('account_id',category_record.asset_account_id,'debit',asset_record.original_cost,'credit',0,'description',asset_record.asset_code||' capitalization'),jsonb_build_object('account_id',p_counter_account_id,'debit',0,'credit',asset_record.original_cost,'description','Capitalization counter account'))); perform set_config('app.business_asset_action','asset_write',true); update public.business_fixed_assets set status='active',capitalization_counter_account_id=p_counter_account_id,capitalization_journal_entry_id=journal_id,activated_by=actor_id,activated_at=now(),updated_by=actor_id where business_id=p_business_id and id=p_asset_id returning*into asset_record; perform private.write_business_asset_audit(p_business_id,p_asset_id,null,'fixed_asset_capitalized',jsonb_build_object('journal_entry_id',journal_id,'posting_date',p_posting_date)); return to_jsonb(asset_record)||jsonb_build_object('asset_display_code','AST-'||lpad(asset_record.asset_no::text,8,'0')); end;$$;
